/* ----------调用字体---------- */

@font-face {  font-family: arial; }
@font-face {  font-family: arial; }


/* ----------各种样式---------- */

body { background-color: #fff; color: black; }
.card {
	font: 15px/20px yh;
	background-color:#fff;
	#background-image: none;
	#background-size:100%;
}


.cloze {
	color: #ec6c4f;
	#font-weight: bold;
	border-bottom: 1px solid #ec6c4f;
	-webkit-animation: cloze 0.4s 0s;
	-webkit-animation-fill-mode: forwards;
}
.h1 { font: 22px/22px yh; padding: 0.3em 0em 0.3em 0.5em; }
.h2 { font: 20px/30px yh; padding: 0.3em 0em 0.3em 0.5em; }

.xleft { border-left: 3px solid #ec6c4f; }
.yleft { border-left: 3px solid #338eca; }
.zleft { border-left: 3px solid #4c991b; }
.hleft { border-left: 3px solid #ffd675; }
.kleft { border-left: 3px solid #5daa9f; }
.vleft { border-left: 3px solid #ff5d65; }
.nleft { border-left: 3px solid #55aa7f; }
.mleft { border-left: 3px solid #ffaeb4; }
.oleft { border-left: 3px solid #a489cc; }
.pleft { border-left: 3px solid #ef6457; }


.xcolor { color: #ec6c4f; }
.ycolor { color: #338eca; }
.zcolor { color:#46aa63; }
.hcolor { color: #ffd675; }
.kcolor { color: #5daa9f; }
.vcolor { color: #ff5d65; }
.ncolor { color: #55aa7f; }
.mcolor { color: #ffaeb4; }
.ocolor { color: #a489cc; }
.pcolor { color: #ef6457; }


.ximg { background: none; background-size: 100%; background-repeat: no-repeat; background-position: center; }
.yimg { background: none; background-size: 100%; background-repeat: no-repeat; background-position: center; }
.zimg { background: none; background-size: 100%; background-repeat: no-repeat; background-position: center; }

.btn {
	opacity: 0.8;
	right: 10px;
	bottom: 10px;
	height: 70px;
	width: 70px;
	border: none;
	background: none;
	background-size: 100%;
	position: fixed;
}
	.btn:active { opacity: 0.9; }
.hint { color: #333; }


/* ---------- 其他调整 ---------- */

a { color: #666; }
img { max-width: 100%; vertical-align: middle; }
	.chrome img { max-width: 100%; vertical-align: middle; }
ul,ol { margin-top: 0em; }
li { margin-left: -0.5em; }
i { font-family: palatino; padding: 0 3px 0 0; }
u { text-decoration: none; background-color: #ffff75; border-bottom: 2px solid #ec6c4f; }
uu { border-bottom: 1px solid #ec6c4f; }
hr { height: 1px; width: 100%; display: block; border: 0px solid #fff; vertical-align: middle; margin:5px 0px 10px 0px; background-color: #ccc;}
#time { font-family: yh; float: right; } 


/* ----------夜间模式（Android）---------- */

body.night_mode { background-color: #232323; color:#727272; }
.night_mode .card { background-color: #232323;  color:#727272; }
.night_mode .cloze { color: #a0a0a0; border-bottom: 1px solid #a0a0a0; }

.night_mode .xleft { border-left: 3px solid #a0a0a0; }
.night_mode .yleft { border-left: 3px solid #a0a0a0; }
.night_mode .zleft { border-left: 3px solid #a0a0a0; }

.night_mode .xcolor { #font-weight: bold; color:#a0a0a0; }
.night_mode .ycolor { #font-weight: bold; color:#a0a0a0; }
.night_mode .zcolor { #font-weight: bold; color:#a0a0a0; }

.night_mode .ximg{ background: none; background-size: 100%; background-repeat: no-repeat; background-position: center; }
.night_mode .yimg{ background: none; background-size: 100%; background-repeat: no-repeat; background-position: center; }
.night_mode .zimg{ background: none; background-size: 100%; background-repeat: no-repeat; background-position: center; }

.night_mode .hint { color: #727272; }
.night_mode u { color: #a0a0a0; background-color: #505050; border-bottom: 2px solid #5f5f5f; }
.night_mode uu { border-bottom: 1px solid #5f5f5f; }
.night_mode img { filter: alpha(opacity=30); opacity:0.3;  filter:invert;}
.night_mode audio { filter: alpha(opacity=30); opacity:0.3; }
.night_mode hr { background-color: #484848; }
.night_mode .btn { opacity:0.5; right:10px; bottom:10px; position: fixed; }
.night_mode .btn:active { opacity:0.3; }

/* ----------动画效果---------- */

.slide { position: relative; -webkit-animation: slide 1s 0s; -webkit-animation-fill-mode: forwards; }

@-webkit-keyframes slide {
	0%	{ opacity: 0  ; top: 100px; }
	50%	{ opacity: 0.8; top: -10px; }
	100%	{ opacity: 1.0; top: -3px; }
}

@-webkit-keyframes cloze {
	from	{ opacity: 0; }
	to  	{ opacity: 1; }
}
